  4→#define __RISCV_NN_TYPES_H__
  5→
  6→#include <riscv_nn_activation.h>
  7→
  8→/** RISCV-NN object for the quantized Relu activation */
  9→typedef struct
 10→{
 11→    int32_t min; /**< Min value used to clamp the result */
 12→    int32_t max; /**< Max value used to clamp the result */
 13→} riscv_nn_activation;
 14→
 15→/** RISCV-NN object to contain LSTM specific input parameters related to dimensions */
 16→typedef struct
 17→{
 18→    int32_t max_time;
 19→    int32_t num_inputs;
 20→    int32_t num_batches;
 21→    int32_t num_outputs;
 22→} riscv_nn_lstm_dims;
 23→
 24→/** LSTM guard parameters */
 25→typedef struct
 26→{
 27→    int32_t input_variance;
 28→    int32_t forget_variance;
 29→    int32_t cell_variance;
 30→    int32_t output_variance;
 31→} riscv_nn_lstm_guard_params;
 32→
 33→/** LSTM scratch buffer container */
 34→typedef struct
 35→{
 36→    int16_t *input_gate;
 37→    int16_t *forget_gate;
 38→    int16_t *cell_gate;
 39→    int16_t *output_gate;
 40→} riscv_nn_lstm_context;
 41→
 42→/** Quantized clip value for cell and projection of LSTM input. Zero value means no clipping. */
 43→typedef struct
 44→{
 45→    int16_t cell;
 46→    int8_t projection;
 47→} riscv_nn_lstm_clip_params;
 48→
 49→/** RISCV-NN object for quantization parameters */
 50→typedef struct
 51→{
 52→    int32_t multiplier; /**< Multiplier value */
 53→    int32_t shift;      /**< Shift value */
 54→} riscv_nn_scaling;
 55→
 56→/** RISCV-NN norm layer coefficients */
 57→typedef struct
 58→{
 59→    int16_t *input_weight;
 60→    int16_t *forget_weight;
 61→    int16_t *cell_weight;
 62→    int16_t *output_weight;
 63→} riscv_nn_layer_norm;
 64→
 65→/** Parameters for integer LSTM, as defined in TFLM */
 66→typedef struct
 67→{
 68→    int32_t time_major; /**< Nonzero (true) if first row of data is timestamps for input */
 69→    riscv_nn_scaling input_to_input_scaling;
 70→    riscv_nn_scaling input_to_forget_scaling;
 71→    riscv_nn_scaling input_to_cell_scaling;
 72→    riscv_nn_scaling input_to_output_scaling;
 73→    riscv_nn_scaling recurrent_to_input_scaling;
 74→    riscv_nn_scaling recurrent_to_forget_scaling;
 75→    riscv_nn_scaling recurrent_to_cell_scaling;
 76→    riscv_nn_scaling recurrent_to_output_scaling;
 77→    riscv_nn_scaling cell_to_input_scaling;
 78→    riscv_nn_scaling cell_to_forget_scaling;
 79→    riscv_nn_scaling cell_to_output_scaling;
 80→    riscv_nn_scaling projection_scaling;
 81→    riscv_nn_scaling hidden_scaling;
 82→    riscv_nn_scaling layer_norm_input_scaling;  /**< layer normalization for input layer */
 83→    riscv_nn_scaling layer_norm_forget_scaling; /**< layer normalization for forget gate */
 84→    riscv_nn_scaling layer_norm_cell_scaling;   /**< layer normalization for cell */
 85→    riscv_nn_scaling layer_norm_output_scaling; /**< layer normalization for outpus layer */
 86→
 87→    int32_t cell_state_shift;
 88→    int32_t hidden_offset;
 89→    int32_t output_state_offset;
 90→
 91→    riscv_nn_lstm_clip_params clip;
 92→    riscv_nn_lstm_guard_params guard;
 93→    riscv_nn_layer_norm layer_norm;
 94→
 95→    /* Effective bias is precalculated as bias + zero_point * weight.
 96→    Only applicable to when input/output are s8 and weights are s16 */
 97→    const int32_t *i2i_effective_bias; /**< input to input effective bias */
 98→    const int32_t *i2f_effective_bias; /**< input to forget gate effective bias */
 99→    const int32_t *i2c_effective_bias; /**< input to cell effective bias */
100→    const int32_t *i2o_effective_bias; /**< input to output effective bias */
101→
102→    const int32_t *r2i_effective_bias; /**< recurrent gate to input effective bias */
103→    const int32_t *r2f_effective_bias; /**< recurrent gate to forget gate effective bias */
104→    const int32_t *r2c_effective_bias; /**< recurrent gate to cell effective bias */
105→    const int32_t *r2o_effective_bias; /**< recurrent gate to output effective bias */
106→
107→    const int32_t *projection_effective_bias;
108→
109→    /* Not precalculated bias */
110→    const int32_t *input_gate_bias;
111→    const int32_t *forget_gate_bias;
112→    const int32_t *cell_gate_bias;
113→    const int32_t *output_gate_bias;
114→
115→    /* Activation min and max */
116→    riscv_nn_activation activation;
117→
118→} riscv_nn_lstm_params;
119→
120→/** RISCV-NN object for LSTM gate parameters*/
121→typedef struct
122→{
123→    int32_t input_multiplier;
124→    int32_t input_shift;
125→    const void *input_weights;
126→    const void *input_effective_bias;   /**< Bias added with precomputed kernel_sum * lhs_offset*/
127→
128→    int32_t hidden_multiplier;
129→    int32_t hidden_shift;
130→    const void *hidden_weights;
131→    const void *hidden_effective_bias;  /**< Precomputed kernel_sum * lhs_offset*/
132→
133→    const void *bias;
134→    riscv_nn_activation_fun activation_type;
135→} riscv_nn_lstm_gate;
136→
137→/** RISCV-NN object for LSTM parameters*/
138→typedef struct
139→{
140→    int32_t time_major;     /**< 0 if first dimension is batch, else first dimension is time */
141→    int32_t batch_size;
142→    int32_t time_steps;
143→    int32_t input_size;     /**< Size of new data input into the LSTM cell*/
144→    int32_t hidden_size;    /**< Size of output from the LSTM cell, used as output and recursively into the next time step*/
145→
146→    int32_t input_offset;
147→
148→    int32_t forget_to_cell_multiplier;
149→    int32_t forget_to_cell_shift;
150→    int32_t input_to_cell_multiplier;
151→    int32_t input_to_cell_shift;
152→    int32_t cell_clip;      /**< Min/max value of cell output*/
153→    int32_t cell_scale_power;
154→
155→    int32_t output_multiplier;
156→    int32_t output_shift;
157→    int32_t output_offset;
158→
159→    riscv_nn_lstm_gate forget_gate;
160→    riscv_nn_lstm_gate input_gate;
161→    riscv_nn_lstm_gate cell_gate;
162→    riscv_nn_lstm_gate output_gate;
163→} riscv_nn_lstm_params2;
164→
165→/** RISCV-NN object for LSTM scratch buffers*/
166→typedef struct
167→{
168→    void *temp1;
169→    void *temp2;
170→    void *cell_state;
171→} riscv_nn_lstm_context2;
172→
173→typedef enum
174→{
175→    NN_WZYX_2_WZXY = 0,  // perm:[0,1,3,2]
176→    NN_WZYX_2_WYZX = 1,  // perm:[0,2,1,3]
177→    NN_WZYX_2_WYXZ = 2,  // perm:[0,2,3,1]
178→    NN_WZYX_2_WXZY = 3,  // perm:[0,3,1,2]
179→    NN_WZYX_2_WXYZ = 4,  // perm:[0,3,2,1]
180→    NN_WZYX_2_ZWXY = 5,  // perm:[1,0,3,2]
181→	NN_WZYX_2_ZWYX = 6,  // perm:[1,0,2,3]
182→	NN_WZYX_2_YWZX = 7,  // perm:[2,0,1,3]
183→} riscv_nn_transpose_format;
184→
185→#endif // RISCV_NN_TYPES_H

